import{c as e,Q as d,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Entity Status Reference","description":"","frontmatter":{},"headers":[],"relativePath":"entity-statuses.md","filePath":"entity-statuses.md","lastUpdated":1778828280000}'),o={name:"entity-statuses.md"};function n(i,t,s,c,l,h){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="entity-status-reference" tabindex="-1">Entity Status Reference <a class="header-anchor" href="#entity-status-reference" aria-label="Permalink to &quot;Entity Status Reference&quot;">​</a></h1><p>A glossary of every status value you&#39;ll see in the Console, what it means, and what you can do from it. Written for business users — no code, no internal jargon.</p><p>A handful of states are <strong>terminal/dead</strong> and are filtered out of the command-palette search by default (they still appear on their dedicated list pages). Those are flagged below.</p><hr><h2 id="customer" tabindex="-1">Customer <a class="header-anchor" href="#customer" aria-label="Permalink to &quot;Customer&quot;">​</a></h2><p>A customer is the top-level account that owns one or more tenants.</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Typical actions</th></tr></thead><tbody><tr><td><code>active</code></td><td>Currently a paying / live customer. Billing runs, tenants are usable.</td><td>Normal operations.</td></tr><tr><td><code>suspended</code></td><td>Temporarily paused — usually for non-payment, contract dispute, or a manual ops hold. Tenants typically frozen.</td><td>Restore to <code>active</code> once the underlying issue is resolved, or progress to <code>churned</code>.</td></tr><tr><td><code>churned</code> 🪦</td><td>Customer has left. No billing, no expected return.</td><td>Read-only — kept for history and audit. <strong>Hidden from palette.</strong></td></tr></tbody></table><hr><h2 id="tenant" tabindex="-1">Tenant <a class="header-anchor" href="#tenant" aria-label="Permalink to &quot;Tenant&quot;">​</a></h2><p>A tenant is a single workspace under a customer. It lives on exactly one instance.</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Typical actions</th></tr></thead><tbody><tr><td><code>requested</code></td><td>A tenant has been requested but not yet picked up by provisioning.</td><td>Wait for the provisioning worker, or cancel the request.</td></tr><tr><td><code>provisioning</code></td><td>Currently being set up (DB seed, bucket creation, etc.). Brief, but visible.</td><td>Wait. If stuck, check the migration job.</td></tr><tr><td><code>active</code></td><td>Live and usable by end-users.</td><td>Normal operations.</td></tr><tr><td><code>suspended</code></td><td>Temporarily disabled — login blocked. Data retained.</td><td>Re-activate, or progress to <code>archived</code>.</td></tr><tr><td><code>archived</code> 🪦</td><td>End of life. Data may be retained for compliance but the workspace is closed.</td><td>Read-only — restore requires manual intervention. <strong>Hidden from palette.</strong></td></tr><tr><td><code>import_failed</code> 🪦</td><td>Tenant import (from a migration job) failed and was not recovered.</td><td>Retry the import or archive. <strong>Hidden from palette.</strong></td></tr></tbody></table><hr><h2 id="user-internal-customer" tabindex="-1">User (Internal &amp; Customer) <a class="header-anchor" href="#user-internal-customer" aria-label="Permalink to &quot;User (Internal &amp; Customer)&quot;">​</a></h2><p>Users come in two flavours — internal users (your team) and customer users (their team). Both share the same status set.</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Typical actions</th></tr></thead><tbody><tr><td><code>invited</code></td><td>Invitation sent, user hasn&#39;t accepted/logged in yet.</td><td>Resend invite, revoke.</td></tr><tr><td><code>active</code></td><td>Logged in at least once and currently has access.</td><td>Normal operations.</td></tr><tr><td><code>suspended</code></td><td>Access temporarily blocked. Account retained, can be restored.</td><td>Re-activate, or progress to <code>deactivated</code>.</td></tr><tr><td><code>deactivated</code> 🪦</td><td>Permanent removal from access lists. Identity preserved for audit.</td><td>Read-only — kept so historical actions still attribute to a name. <strong>Hidden from palette.</strong></td></tr></tbody></table><hr><h2 id="instance" tabindex="-1">Instance <a class="header-anchor" href="#instance" aria-label="Permalink to &quot;Instance&quot;">​</a></h2><p>An instance is one running deployment of the platform serving a set of tenants.</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Typical actions</th></tr></thead><tbody><tr><td><code>provisioning</code></td><td>Newly registered, waiting for its first heartbeat.</td><td>Wait for it to come online.</td></tr><tr><td><code>active</code></td><td>Healthy, serving traffic.</td><td>Normal operations.</td></tr><tr><td><code>degraded</code></td><td>Heartbeat missing, error rate high, or health check failing. Still serving but unhappy.</td><td>Investigate (check logs, metrics, oncall).</td></tr><tr><td><code>maintenance</code></td><td>Manually placed into a maintenance window — traffic typically drained.</td><td>Complete the maintenance and restore to <code>active</code>.</td></tr><tr><td><code>decommissioned</code> 🪦</td><td>Permanently retired. No longer accepting traffic.</td><td>Read-only — kept for audit.</td></tr></tbody></table><hr><h2 id="migration-job" tabindex="-1">Migration Job <a class="header-anchor" href="#migration-job" aria-label="Permalink to &quot;Migration Job&quot;">​</a></h2><p>Jobs handle bulk tenant operations: import, export, clone, instance-replace, etc.</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Typical actions</th></tr></thead><tbody><tr><td><code>queued</code></td><td>Created, waiting for a worker to pick it up.</td><td>Wait, or cancel.</td></tr><tr><td><code>running</code></td><td>Actively executing.</td><td>Watch the live log.</td></tr><tr><td><code>succeeded</code></td><td>Finished cleanly.</td><td>Review the report; close the loop.</td></tr><tr><td><code>failed</code></td><td>Stopped mid-flight with errors.</td><td>Inspect the failure, fix the root cause, then <strong>rerun</strong> — rerun resumes only the failed work.</td></tr></tbody></table><hr><h2 id="release" tabindex="-1">Release <a class="header-anchor" href="#release" aria-label="Permalink to &quot;Release&quot;">​</a></h2><p>A release rolls a new version out across stages (e.g. dev → qa → prod).</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Typical actions</th></tr></thead><tbody><tr><td><code>draft</code></td><td>Not yet started.</td><td>Trigger when ready.</td></tr><tr><td><code>in_progress</code></td><td>Rolling through stages.</td><td>Monitor stages; approve gates.</td></tr><tr><td><code>paused</code></td><td>Manually halted between stages — common when waiting on validation.</td><td>Resume, or cancel.</td></tr><tr><td><code>completed</code></td><td>Successfully reached the final stage everywhere.</td><td>Done.</td></tr><tr><td><code>failed</code></td><td>A stage failed and stopped the rollout.</td><td>Investigate, retry, or roll back.</td></tr><tr><td><code>rolled_back</code></td><td>Manually reverted to the previous version.</td><td>Capture lessons; plan the next attempt.</td></tr><tr><td><code>cancelled</code></td><td>Aborted before completion.</td><td>Document why; trigger a fresh release if needed.</td></tr></tbody></table><hr><h2 id="invoice" tabindex="-1">Invoice <a class="header-anchor" href="#invoice" aria-label="Permalink to &quot;Invoice&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>draft</code></td><td>Being built — not yet visible to customer.</td></tr><tr><td><code>issued</code></td><td>Sent to customer; payment expected.</td></tr><tr><td><code>paid</code></td><td>Settled in full.</td></tr><tr><td><code>overdue</code></td><td>Past due date, unpaid.</td></tr><tr><td><code>void</code></td><td>Cancelled — never to be paid.</td></tr><tr><td><code>refunded</code></td><td>Previously paid, money returned.</td></tr></tbody></table><hr><h2 id="payment" tabindex="-1">Payment <a class="header-anchor" href="#payment" aria-label="Permalink to &quot;Payment&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>pending</code></td><td>Submitted to the payment provider, awaiting confirmation.</td></tr><tr><td><code>succeeded</code></td><td>Cleared.</td></tr><tr><td><code>failed</code></td><td>Provider rejected (insufficient funds, expired card, etc.).</td></tr><tr><td><code>refunded</code></td><td>Money returned to the customer.</td></tr></tbody></table><hr><h2 id="notes-for-non-technical-readers" tabindex="-1">Notes for non-technical readers <a class="header-anchor" href="#notes-for-non-technical-readers" aria-label="Permalink to &quot;Notes for non-technical readers&quot;">​</a></h2><ul><li><strong>🪦 means &quot;dead state&quot;</strong> — the entity is preserved for history but is no longer expected to be acted on. The Console hides these from search-by-default views (like the command palette) so you can find live records faster. They&#39;re still accessible from the entity&#39;s dedicated list page.</li><li><strong><code>active</code> is always the live, normal state</strong> across every entity.</li><li><strong>Suspension is reversible</strong>, deactivation/archival/churn/decommissioning is not (without manual intervention).</li><li>If you see a status not listed here, ping engineering — it may be a new state added after this doc was last updated.</li></ul>',36)])])}const m=e(o,[["render",n]]);export{p as __pageData,m as default};
